package com.spendwise.prototype.ui; import android.os.Bundle; import android.view.View; import android.widget.*; import androidx.fragment.app.Fragment; import androidx.lifecycle.lifecycleScope; import com.spendwise.prototype.R; import com.spendwise.prototype.data.*; import kotlinx.coroutines.flow.first; import kotlinx.coroutines.launch; class GoalsFragment:Fragment(R.layout.fragment_goals){ override fun onViewCreated(v:View,b:Bundle?){ val db=AppDatabase.get(requireContext()); val sp=v.findViewById<Spinner>(R.id.spGoalCat); var cs=emptyList<Category>(); lifecycleScope.launch{ cs=db.categoryDao().getAll().first(); sp.adapter=ArrayAdapter(requireContext(),android.R.layout.simple_spinner_item,cs.map{it.name}) }; v.findViewById<Button>(R.id.btnSetGoal).setOnClickListener{ val min=v.findViewById<EditText>(R.id.etMin).text.toString().toDoubleOrNull()?:0.0; val max=v.findViewById<EditText>(R.id.etMax).text.toString().toDoubleOrNull()?:0.0; val id=cs.getOrNull(sp.selectedItemPosition)?.id?:1L; lifecycleScope.launch{ db.goalDao().set(BudgetGoal(id,min,max)); v.findViewById<TextView>(R.id.tvGoalStatus).text="Goal saved: R$min - R$max" } } } }